class Solution {
public:
    vector<bool> friendRequests(int n, vector<vector<int>>& restrictions, vector<vector<int>>& requests) {
        vector<int> parent(n);
        for (int i = 0; i < n; ++i) parent[i] = i;

        auto find = [&](int u) {
            while (parent[u] != u) {
                parent[u] = parent[parent[u]];
                u = parent[u];
            }
            return u;
        };

        vector<unordered_set<int>> restricted(n);
        for (const auto& r : restrictions) {
            int x = r[0], y = r[1];
            restricted[x].insert(y);
            restricted[y].insert(x);
        }

        vector<bool> res;
        for (const auto& req : requests) {
            int u = req[0], v = req[1];
            int pu = find(u), pv = find(v);
            if (pu == pv) {
                res.push_back(true);
                continue;
            }
            bool ok = true;
            for (int x : restricted[pu]) {
                if (find(x) == pv) {
                    ok = false;
                    break;
                }
            }
            if (ok) {
                parent[pu] = pv;
                res.push_back(true);
            } else {
                res.push_back(false);
            }
        }
        return res;
    }
};
